'use client';

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Loader2, Send } from 'lucide-react';

const formSchema = z.object({
  name: z.string().min(2, 'El nombre debe tener al menos 2 caracteres'),
  email: z.string().email('Email inválido'),
  phone: z.string().optional(),
  type: z.enum(['Veterinaria', 'E-commerce', 'Agendamiento', 'Otro', ''], {
    errorMap: () => ({ message: 'Selecciona un tipo de web' })
  }).refine(val => val !== '', { message: 'Selecciona un tipo de web' }),
  budget: z.enum(['$2-3k', '$4-6k', '$7k+', 'No sé', ''], {
    errorMap: () => ({ message: 'Selecciona un presupuesto aproximado' })
  }).refine(val => val !== '', { message: 'Selecciona un presupuesto aproximado' }),
  message: z.string().min(10, 'El mensaje debe tener al menos 10 caracteres')
});

type FormData = z.infer<typeof formSchema>;

export default function ContactForm() {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);
  const [submitError, setSubmitError] = useState(false);

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors }
  } = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      type: '',
      budget: ''
    }
  });

  const onSubmit = async (data: FormData) => {
    setIsSubmitting(true);
    setSubmitSuccess(false);
    setSubmitError(false);

    try {
      const response = await fetch('/api/contact', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(data),
      });

      if (!response.ok) throw new Error('Network error');
      
      setSubmitSuccess(true);
      reset();
    } catch (error) {
      setSubmitError(true);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <section id="contact" className="py-24 relative overflow-hidden bg-black/40">
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-primary/10 rounded-full blur-[128px] -z-10 pointer-events-none" />
      
      <div className="container mx-auto px-4 md:px-6 max-w-3xl relative z-10">
        <div className="text-center mb-12">
          <h2 className="text-3xl md:text-4xl font-bold mb-4">Inicia tu <span className="text-primary">Proyecto</span></h2>
          <p className="text-muted-foreground text-lg">
            Completa el formulario y te responderé en menos de 24 horas.
          </p>
        </div>

        <div className="glass rounded-3xl p-8 md:p-12 relative">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary via-secondary to-primary rounded-t-3xl" />
          
          {submitSuccess ? (
            <div className="text-center py-12">
              <div className="w-20 h-20 bg-green-500/20 text-green-500 rounded-full flex items-center justify-center mx-auto mb-6">
                <Send className="w-10 h-10" />
              </div>
              <h3 className="text-2xl font-bold mb-2">¡Mensaje Enviado!</h3>
              <p className="text-muted-foreground">Gracias por contactarme. Me pondré en contacto contigo muy pronto.</p>
              <button 
                onClick={() => setSubmitSuccess(false)}
                className="mt-8 px-6 py-2 rounded-full border border-white/20 hover:bg-white/10 transition-colors"
              >
                Enviar otro mensaje
              </button>
            </div>
          ) : (
            <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-white/80">Nombre Completo *</label>
                  <input 
                    {...register('name')} 
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-primary/50 text-white transition-all"
                    placeholder="Tu nombre"
                  />
                  {errors.name && <p className="text-red-400 text-xs">{errors.name.message}</p>}
                </div>
                
                <div className="space-y-2">
                  <label className="text-sm font-medium text-white/80">Correo Electrónico *</label>
                  <input 
                    {...register('email')} 
                    type="email"
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-primary/50 text-white transition-all"
                    placeholder="tu@email.com"
                  />
                  {errors.email && <p className="text-red-400 text-xs">{errors.email.message}</p>}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-white/80">Teléfono (Opcional)</label>
                  <input 
                    {...register('phone')} 
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-primary/50 text-white transition-all"
                    placeholder="+57 300 000 0000"
                  />
                </div>
                
                <div className="space-y-2">
                  <label className="text-sm font-medium text-white/80">Tipo de Proyecto *</label>
                  <select 
                    {...register('type')} 
                    className="w-full bg-[#1A1A1A] border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-primary/50 text-white transition-all appearance-none"
                  >
                    <option value="" disabled>Selecciona una opción</option>
                    <option value="Veterinaria">Veterinaria</option>
                    <option value="E-commerce">E-commerce</option>
                    <option value="Agendamiento">Agendamiento / Reservas</option>
                    <option value="Otro">Otro</option>
                  </select>
                  {errors.type && <p className="text-red-400 text-xs">{errors.type.message}</p>}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-white/80">Presupuesto Aproximado *</label>
                <select 
                  {...register('budget')} 
                  className="w-full bg-[#1A1A1A] border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-primary/50 text-white transition-all appearance-none"
                >
                  <option value="" disabled>Selecciona una opción</option>
                  <option value="$2-3k">$2,000 - $3,500 (Básico)</option>
                  <option value="$4-6k">$4,000 - $6,500 (Profesional)</option>
                  <option value="$7k+">$7,000+ (Custom)</option>
                  <option value="No sé">No estoy seguro aún</option>
                </select>
                {errors.budget && <p className="text-red-400 text-xs">{errors.budget.message}</p>}
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-white/80">Mensaje / Detalles del Proyecto *</label>
                <textarea 
                  {...register('message')} 
                  rows={4}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-primary/50 text-white transition-all resize-none"
                  placeholder="Cuéntame sobre tu idea o requerimientos..."
                ></textarea>
                {errors.message && <p className="text-red-400 text-xs">{errors.message.message}</p>}
              </div>
              
              {submitError && (
                <p className="text-red-400 text-sm text-center">Hubo un error al enviar el mensaje. Por favor intenta de nuevo.</p>
              )}

              <button 
                type="submit" 
                disabled={isSubmitting}
                className="w-full py-4 rounded-xl bg-primary text-white font-bold text-lg hover:bg-primary/90 transition-all shadow-[0_0_20px_rgba(37,99,235,0.4)] disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              >
                {isSubmitting ? (
                  <><Loader2 className="w-5 h-5 animate-spin" /> Enviando...</>
                ) : (
                  <><Send className="w-5 h-5" /> Enviar Solicitud</>
                )}
              </button>
            </form>
          )}
        </div>
      </div>
    </section>
  );
}

'use client';

import { useState } from 'react';
import { ChevronDown } from 'lucide-react';

const faqs = [
  {
    question: "¿Qué significa desarrollo web Full-Stack?",
    answer: "Significa que me encargo del proyecto de principio a fin: tanto de la parte visual (Frontend) que interactúa con el usuario, como del servidor, bases de datos y lógica de negocio (Backend)."
  },
  {
    question: "¿Cuál es la diferencia entre los paquetes?",
    answer: "El Básico está orientado a quien necesita presencia online rápida sin funcionalidades complejas. El Profesional incluye APIs, panel de administración y más integración, ideal para negocios medianos. El Custom Completo es un desarrollo a la medida desde cero (Ej: un CRM interno o ERP)."
  },
  {
    question: "¿Por qué utilizas plantillas en los paquetes básicos?",
    answer: "Utilizar bases sólidas de código que ya han sido probadas (plantillas) me permite reducir los tiempos de entrega drásticamente y bajar los costos, sin sacrificar la calidad ni el rendimiento del sistema."
  },
  {
    question: "¿Dónde estará alojada mi web?",
    answer: "Por defecto, despliego todos los proyectos en Vercel, que es la plataforma número uno del mundo para alojamiento de aplicaciones modernas. Es extremadamente rápida, escalable y segura."
  },
  {
    question: "¿El código fuente me pertenece?",
    answer: "Sí, en todos los paquetes el código final es 100% de tu propiedad. Se entrega en un repositorio privado de GitHub a nombre tuyo o de tu empresa."
  },
  {
    question: "¿Ofreces soporte después del lanzamiento?",
    answer: "Dependiendo del paquete, ofrezco entre 1 y 3 meses de soporte post-lanzamiento para corregir cualquier bug detectado o realizar ajustes menores sin costo adicional."
  }
];

export default function FAQ() {
  const [openIndex, setOpenIndex] = useState<number | null>(null);

  const toggleFAQ = (index: number) => {
    setOpenIndex(openIndex === index ? null : index);
  };

  return (
    <section className="py-24 relative">
      <div className="container mx-auto px-4 md:px-6 max-w-4xl">
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-4xl font-bold mb-4">Preguntas <span className="text-primary">Frecuentes</span></h2>
          <p className="text-muted-foreground text-lg">Resolvemos tus dudas antes del desarrollo.</p>
        </div>

        <div className="space-y-4">
          {faqs.map((faq, index) => (
            <div 
              key={index}
              className={\`glass rounded-xl overflow-hidden transition-all duration-300 \${openIndex === index ? 'border-primary/50' : 'border-white/10'}\`}
            >
              <button
                className="w-full px-6 py-5 text-left flex justify-between items-center focus:outline-none"
                onClick={() => toggleFAQ(index)}
              >
                <span className="font-semibold text-lg pr-8">{faq.question}</span>
                <ChevronDown 
                  className={\`w-5 h-5 text-primary transition-transform duration-300 \${openIndex === index ? 'rotate-180' : ''}\`} 
                />
              </button>
              
              <div 
                className={\`overflow-hidden transition-all duration-300 \${openIndex === index ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'}\`}
              >
                <div className="px-6 pb-6 text-muted-foreground">
                  {faq.answer}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

import { ExternalLink, Sparkles } from 'lucide-react';

const projects = [
  {
    title: "PetCare System",
    description: "Sistema de agendamiento de citas veterinarias con portal administrativo en tiempo real.",
    link: "https://petcare-system.vercel.app/",
    tags: ["Node.js", "MongoDB", "React", "Next.js"],
    highlighted: true,
  },
  {
    title: "E-Commerce Pro",
    description: "Tienda en línea de alto rendimiento con carrito, pasarela de pagos e inventario.",
    link: "#",
    tags: ["Next.js", "Stripe", "Supabase", "Tailwind"],
    highlighted: false,
  },
  {
    title: "Agendamiento Dental",
    description: "Plataforma de reservas para clínicas con recordatorios por correo electrónico automáticos.",
    link: "#",
    tags: ["React", "Express", "PostgreSQL", "Nodemailer"],
    highlighted: false,
  }
];

export default function Portfolio() {
  return (
    <section id="portfolio" className="py-24 relative bg-black/40">
      <div className="container mx-auto px-4 md:px-6">
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-4xl font-bold mb-4">Caso de <span className="text-primary">Éxito & Portafolio</span></h2>
          <p className="text-muted-foreground text-lg max-w-2xl mx-auto">
            Explora algunos de los sistemas desarrollados y lanzados a producción. 
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {projects.map((project, idx) => (
            <div 
              key={idx} 
              className={\`group relative overflow-hidden rounded-2xl transition-all duration-300 \${project.highlighted ? 'glass neon-border ring-2 ring-primary/50 md:col-span-2 lg:col-span-1 shadow-[0_0_30px_rgba(37,99,235,0.15)]' : 'bg-white/5 border border-white/10 hover:border-white/30'}\`}
            >
              <div className="p-8 h-full flex flex-col justify-between">
                <div>
                  {project.highlighted && (
                    <div className="inline-flex items-center gap-1 px-3 py-1 rounded-full bg-primary/20 text-primary text-xs font-bold mb-4 border border-primary/30">
                      <Sparkles className="w-3 h-3" /> Proyecto Estrella
                    </div>
                  )}
                  <h3 className="text-2xl font-bold mb-3">{project.title}</h3>
                  <p className="text-muted-foreground mb-6">
                    {project.description}
                  </p>
                  <div className="flex flex-wrap gap-2 mb-8">
                    {project.tags.map(tag => (
                      <span key={tag} className="px-2.5 py-1 rounded-md bg-white/5 text-xs font-mono text-white/70 border border-white/10">
                        {tag}
                      </span>
                    ))}
                  </div>
                </div>
                
                <a 
                  href={project.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  className={\`inline-flex items-center gap-2 font-medium transition-colors \${project.highlighted ? 'text-primary hover:text-primary/80' : 'text-white/80 hover:text-white'}\`}
                >
                  Ver Proyecto en Vivo <ExternalLink className="w-4 h-4" />
                </a>
              </div>
              
              {/* Decorative gradient orb for the highlighted card */}
              {project.highlighted && (
                <div className="absolute -bottom-20 -right-20 w-64 h-64 bg-primary/20 rounded-full blur-3xl -z-10 group-hover:bg-primary/30 transition-colors" />
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default function Technologies() {
  const techs = [
    { name: "Node.js", color: "hover:text-[#339933] hover:border-[#339933]/50" },
    { name: "MongoDB", color: "hover:text-[#47A248] hover:border-[#47A248]/50" },
    { name: "Supabase", color: "hover:text-[#3ECF8E] hover:border-[#3ECF8E]/50" },
    { name: "React", color: "hover:text-[#61DAFB] hover:border-[#61DAFB]/50" },
    { name: "Next.js", color: "hover:text-white hover:border-white/50" },
    { name: "Vercel", color: "hover:text-white hover:border-white/50" },
    { name: "Stripe", color: "hover:text-[#008CDD] hover:border-[#008CDD]/50" },
    { name: "Tailwind CSS", color: "hover:text-[#06B6D4] hover:border-[#06B6D4]/50" },
    { name: "TypeScript", color: "hover:text-[#3178C6] hover:border-[#3178C6]/50" },
    { name: "Nodemailer", color: "hover:text-white hover:border-white/50" }
  ];

  return (
    <section className="py-20 bg-white/[0.02] border-y border-white/5">
      <div className="container mx-auto px-4 md:px-6">
        <p className="text-center text-sm font-medium text-muted-foreground uppercase tracking-widest mb-10">
          Stack Tecnológico Moderno
        </p>
        <div className="flex flex-wrap justify-center gap-4 md:gap-6">
          {techs.map((tech) => (
            <div 
              key={tech.name}
              className={\`px-6 py-3 rounded-xl glass text-muted-foreground font-semibold tracking-wide transition-all duration-300 cursor-default shadow-sm \${tech.color} hover:neon-border\`}
            >
              {tech.name}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

import { Star } from 'lucide-react';

const testimonials = [
  {
    quote: "Excelente trabajo. Mi web está en vivo y los clientes pueden agendar citas directamente. Muy recomendado.",
    name: "María López",
    role: "CEO Clínica Veterinaria",
    rating: 5,
  },
  {
    quote: "Necesitaba una tienda online en 2 semanas y la tenía. Sistema de pagos perfecto. Gracias!",
    name: "Carlos Rodríguez",
    role: "E-commerce Founder",
    rating: 5,
  },
  {
    quote: "Escalable y profesional. Nuestro negocio creció 40% tras tener una web como esta, los tiempos de carga son increíbles.",
    name: "Ana Sánchez",
    role: "Directora de Marketing",
    rating: 5,
  }
];

export default function Testimonials() {
  return (
    <section className="py-24 relative overflow-hidden">
      <div className="container mx-auto px-4 md:px-6">
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-4xl font-bold mb-4">Lo que dicen los <span className="text-primary">Clientes</span></h2>
          <p className="text-muted-foreground text-lg max-w-2xl mx-auto">
            Historias de éxito de negocios que escalaron sus operaciones con nosotros.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {testimonials.map((testimonial, idx) => (
            <div key={idx} className="glass p-8 rounded-2xl relative group hover:-translate-y-2 transition-transform duration-300">
              <div className="absolute top-0 right-0 p-8 opacity-10 font-serif text-8xl text-primary leading-none group-hover:text-secondary group-hover:opacity-20 transition-colors">
                "
              </div>
              
              <div className="flex gap-1 mb-6 relative z-10">
                {[...Array(testimonial.rating)].map((_, i) => (
                  <Star key={i} className="w-5 h-5 fill-secondary text-secondary" />
                ))}
              </div>
              
              <p className="text-lg italic mb-8 relative z-10 text-white/90">
                "{testimonial.quote}"
              </p>
              
              <div className="flex items-center gap-4 relative z-10">
                <div className="w-12 h-12 rounded-full bg-gradient-to-tr from-primary to-secondary flex items-center justify-center text-white font-bold text-lg">
                  {testimonial.name.charAt(0)}
                </div>
                <div>
                  <h4 className="font-bold">{testimonial.name}</h4>
                  <p className="text-sm text-primary">{testimonial.role}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
